import React, { useEffect, useState } from "react";
import { Table, Select, Button, Input, Tag, Avatar, Card, Tooltip } from "antd";
import {
  User,
  Search,
  Eye,
  Edit,
  Trash2,
  ShieldCheck,
  Mail,
  Phone,
  Activity,
  ArrowRight,
  MoreVertical,
  ChevronRight,
  Filter,
  Download
} from "lucide-react";
import { useDispatch, useSelector } from "react-redux";
import {
  deleteUser,
  getUsers,
  updateUserStatus,
} from "../../features/UserList/UserListSlice";
import { useNavigate } from "react-router-dom";
import CustomModal from "../../components/CustomModal";

const { Option } = Select;

const UserList = ({ role }) => {
  const [open, setOpen] = useState(false);
  const [userId, setUserId] = useState("");
  const [searchText, setSearchText] = useState("");
  const [selectedRowKeys, setSelectedRowKeys] = useState([]);
  const dispatch = useDispatch();
  const navigate = useNavigate();

  useEffect(() => {
    dispatch(getUsers(role));
  }, [dispatch, role]);

  const userState = useSelector((state) => state?.userList?.userLists) || {};

  const columns = [
    {
      title: "OPERATIONAL IDENTITY",
      dataIndex: "name",
      width: 350,
      render: (_, record) => (
        <div className="flex items-center gap-5">
          <div className="relative">
            <Avatar
              size={56}
              src={`https://api.dicebear.com/7.x/initials/svg?seed=${record.firstname}&backgroundColor=f1f5f9&textColor=2563eb`}
              className="rounded-2xl border-2 border-white shadow-md ring-1 ring-slate-100"
            />
            <div className={`absolute -bottom-1 -right-1 w-4 h-4 rounded-full border-2 border-white ${record.isActive ? 'bg-emerald-500' : 'bg-slate-300'}`} />
          </div>
          <div className="flex flex-col">
            <span className="font-extrabold text-slate-900 text-[16px] leading-tight tracking-tight group-hover:text-blue-600 transition-colors">
              {record.firstname} {record.lastname}
            </span>
            <div className="flex items-center gap-2 mt-1.5">
               <span className="text-[10px] font-black text-blue-600 bg-blue-50 border border-blue-100 px-2 py-0.5 rounded-md uppercase tracking-wider">
                 {role}
               </span>
               <span className="text-[11px] text-slate-400 font-bold uppercase tracking-tight">
                 ID: {record.userId.substring(0, 8)}
               </span>
            </div>
          </div>
        </div>
      ),
      sorter: (a, b) => a.firstname.localeCompare(b.firstname),
    },
    {
      title: "CONTACT INTEL",
      dataIndex: "email",
      render: (_, record) => (
        <div className="flex flex-col gap-2">
          <div className="flex items-center gap-2.5 text-slate-600 font-bold text-[13px] hover:text-blue-600 transition-colors cursor-pointer group/item">
            <div className="p-1.5 bg-slate-50 rounded-lg group-hover/item:bg-blue-50 transition-colors">
              <Mail size={13} className="text-slate-400 group-hover/item:text-blue-500" />
            </div>
            {record.email}
          </div>
          <div className="flex items-center gap-2.5 text-slate-600 font-bold text-[13px] hover:text-blue-600 transition-colors cursor-pointer group/item">
            <div className="p-1.5 bg-slate-50 rounded-lg group-hover/item:bg-blue-50 transition-colors">
              <Phone size={13} className="text-slate-400 group-hover/item:text-blue-500" />
            </div>
            {record.mobile}
          </div>
        </div>
      ),
    },
    {
      title: "ACCOUNT PROTOCOL",
      dataIndex: "status",
      width: 180,
      render: (text, record) => (
        <Select
          defaultValue={record.isActive ? "active" : "inactive"}
          className="w-full modern-select-v2"
          bordered={false}
          suffixIcon={<MoreVertical size={14} className="text-slate-400" />}
          onChange={(value) => handleChangeStatus(value, record.userId)}
        >
          <Option value="active">
            <div className="flex items-center gap-2">
              <div className="w-2 h-2 rounded-full bg-emerald-500 shadow-sm shadow-emerald-200" />
              <span className="text-[12px] font-black text-slate-700 uppercase tracking-wider">Operational</span>
            </div>
          </Option>
          <Option value="inactive">
             <div className="flex items-center gap-2">
              <div className="w-2 h-2 rounded-full bg-slate-400 shadow-sm" />
              <span className="text-[12px] font-black text-slate-700 uppercase tracking-wider">Restricted</span>
            </div>
          </Option>
        </Select>
      ),
    },
    {
      title: "COMMANDS",
      dataIndex: "action",
      width: 150,
      align: 'right',
      render: (_, record) => (
        <div className="flex items-center justify-end gap-2 pr-4">
          <Tooltip title="Examine Profile">
            <Button
              type="text"
              icon={<Eye size={20} />}
              className="text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-xl w-11 h-11 flex items-center justify-center transition-all duration-300"
              onClick={() => navigate(`/superAdmin/Profile/${record.userId}`)}
            />
          </Tooltip>
          {role === "merchant" && (
            <Tooltip title="Oversee Stores">
              <Button
                type="text"
                icon={<Edit size={20} />}
                className="text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-xl w-11 h-11 flex items-center justify-center transition-all duration-300"
                onClick={() => navigate(`/superAdmin/merchantList/list-Store/${record.userId}`)}
              />
            </Tooltip>
          )}
          <Tooltip title="Revoke Access">
            <Button
              type="text"
              danger
              icon={<Trash2 size={20} />}
              className="text-slate-400 hover:text-rose-600 hover:bg-rose-50 rounded-xl w-11 h-11 flex items-center justify-center transition-all duration-300"
              onClick={() => showModal(record.userId)}
            />
          </Tooltip>
        </div>
      ),
    },
  ];

  const data = (Array.isArray(userState.users) ? userState.users : [])
    .filter(
      (user) =>
        !searchText ||
        `${user.firstname} ${user.lastname}`
          .toLowerCase()
          .includes(searchText.toLowerCase()) ||
        user.email.toLowerCase().includes(searchText.toLowerCase()),
    )
    .map((user, index) => ({
      key: user._id || index + 1,
      userId: user._id,
      firstname: user.firstname,
      lastname: user.lastname,
      email: user.email,
      mobile: user.mobile,
      isActive: user.isActive,
    }));

  const showModal = (id) => {
    setOpen(true);
    setUserId(id);
  };

  const hideModal = () => {
    setOpen(false);
  };

  const handleChangeStatus = (value, userId) => {
    dispatch(updateUserStatus({ id: userId, status: value === "active", role }));
  };

  const deleteUserHandler = (id) => {
    dispatch(deleteUser({ userId: id, role }));
    setOpen(false);
    setTimeout(() => {
      dispatch(getUsers(role));
    }, 500);
  };

  const onSelectChange = (newSelectedRowKeys) => {
    setSelectedRowKeys(newSelectedRowKeys);
  };

  const rowSelection = {
    selectedRowKeys,
    onChange: onSelectChange,
  };

  return (
    <div className="space-y-8 pb-20 animate-in fade-in slide-in-from-bottom-4 duration-700">
      {/* Dynamic Command Center Header */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 items-end">
        <div className="lg:col-span-2">
            <div className="flex items-center gap-3 mb-4">
                <div className="px-3 py-1 bg-blue-600 rounded-lg text-white font-black text-[10px] uppercase tracking-widest">
                    Live System
                </div>
                <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse" />
            </div>
            <h1 className="text-5xl font-black text-slate-900 tracking-tight leading-none mb-4">
                {role} <span className="text-blue-600">Archive</span>
            </h1>
            <p className="text-[16px] text-slate-500 font-bold max-w-xl">
                Managing platform integrity and access controls for authorized {role} accounts in the Pulse Addis ecosystem.
            </p>
        </div>
        <div className="flex flex-col gap-4">
            <div className="relative group">
                <Search
                    className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300 group-hover:text-blue-500 transition-colors"
                    size={20}
                />
                <input
                    type="text"
                    placeholder={`Search the ${role} registry...`}
                    className="pl-14 pr-6 h-16 w-full bg-white border-2 border-slate-100 rounded-[24px] focus:outline-none focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 text-[15px] font-bold transition-all shadow-sm"
                    onChange={(e) => setSearchText(e.target.value)}
                />
            </div>
            <div className="flex gap-2">
                <Button className="flex-1 h-12 rounded-xl border-slate-200 font-black text-[11px] uppercase tracking-widest text-slate-500 flex items-center justify-center gap-2 hover:bg-slate-50">
                    <Filter size={14} /> Refine View
                </Button>
                <Button className="flex-1 h-12 rounded-xl border-slate-200 font-black text-[11px] uppercase tracking-widest text-slate-500 flex items-center justify-center gap-2 hover:bg-slate-50">
                    <Download size={14} /> Export Intel
                </Button>
            </div>
        </div>
      </div>

      <Card className="rounded-[40px] border-none shadow-2xl shadow-slate-200/40 overflow-hidden bg-white mt-12">
        <div className="flex justify-between items-center p-8 border-b border-slate-50 bg-slate-50/30">
          <div className="flex items-center gap-6">
            <div className="flex items-center gap-2">
                <span className="text-[14px] font-black text-slate-900 uppercase">Registry Nodes</span>
                <span className="bg-blue-600 text-white text-[12px] font-black px-3 py-1 rounded-full">{data.length}</span>
            </div>
            {selectedRowKeys.length > 0 && (
                <div className="flex items-center gap-4 animate-in slide-in-from-left-4 duration-300">
                    <div className="w-1 h-8 bg-slate-200 rounded-full" />
                    <span className="text-[13px] font-bold text-blue-600">{selectedRowKeys.length} items selected</span>
                    <Button danger type="primary" size="small" className="rounded-lg font-black text-[10px] uppercase tracking-widest h-8">Bulk Termination</Button>
                </div>
            )}
          </div>
          <div className="flex items-center gap-2 text-slate-400 font-black text-[11px] uppercase tracking-widest">
            <Activity size={14} /> System Health: <span className="text-emerald-500 ml-1">Optimal</span>
          </div>
        </div>

        <Table
          rowSelection={rowSelection}
          columns={columns}
          dataSource={data}
          pagination={{
            pageSize: 10,
            className: "px-8 py-8 border-t border-slate-50",
            itemRender: (page, type, originalElement) => {
                if (type === 'prev') return <span className="font-bold text-[12px] uppercase tracking-widest px-4">Prev</span>;
                if (type === 'next') return <span className="font-bold text-[12px] uppercase tracking-widest px-4">Next</span>;
                return originalElement;
            }
          }}
          className="premium-table"
          scroll={{ x: 1200 }}
        />
      </Card>

      <CustomModal
        hideModal={hideModal}
        open={open}
        performAction={() => deleteUserHandler(userId)}
        title="Authorize Action: Revoke Access"
        content={`Strict Warning: Revoking access for this ${role} will immediately terminate their sessions and disable all linked operational capabilities. This protocol is irreversible.`}
      />

      <style>{`
        .premium-table .ant-table-thead > tr > th {
          background: #fafbfc !important;
          color: #94a3b8 !important;
          font-weight: 800 !important;
          font-size: 11px !important;
          text-transform: uppercase !important;
          letter-spacing: 0.15em !important;
          padding: 24px 32px !important;
          border-bottom: 2px solid #f1f5f9 !important;
        }

        .premium-table .ant-table-tbody > tr > td {
          padding: 24px 32px !important;
          border-bottom: 1px solid #f8fafc !important;
          transition: all 0.3s ease !important;
        }

        .premium-table .ant-table-tbody > tr:hover > td {
          background: #fdfdfe !important;
        }

        .modern-select-v2 {
          background: #f8fafc !important;
          border-radius: 14px !important;
          border: 1.5px solid #e2e8f0 !important;
          height: 44px !important;
          display: flex !important;
          align-items: center !important;
          transition: all 0.3s !important;
        }

        .modern-select-v2:hover {
          border-color: #2563eb !important;
          background: #ffffff !important;
        }

        .ant-table-row-selected td {
          background: #f0f7ff !important;
        }

        .ant-pagination-item-active {
            border-color: #2563eb !important;
            background: #2563eb !important;
        }
        .ant-pagination-item-active a {
            color: white !important;
        }
      `}</style>
    </div>
  );
};

export default UserList;
